using Avalonia;
using Avalonia.Controls;
using Avalonia.Headless;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.Tests;

[Collection("Headless")]
public sealed class HfGateHintLayoutTests
{
    [AvaloniaFact]
    public async Task HfGateHint_IsNotClipped_AtFixedQueuePanelWidth()
    {
        // ── Arrange: repo with config and a task, no HF_TOKEN ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("alpha", "# Alpha\n");

        var env = new DictionaryEnvironmentAccessor();
        using var _ = SettingsTestHelpers.SeedUserEnv(env, repo, "");

        var vm = new MainWindowViewModel
        {
            RootPath = repo.Root,
            EnvironmentAccessor = env
        };
        await vm.LoadInitialAsync();

        // Gate must be visible (no HF_TOKEN).
        Assert.True(vm.ShowHfGate, "HF-gate banner should be visible when HF_TOKEN is absent.");

        // ── Render the window ──
        var window = new MainWindow
        {
            DataContext = vm,
            Width = 1440,
            Height = 900
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Resolve the hint TextBlock ──
        var queuePanel = window.GetVisualDescendants().OfType<QueuePanel>().Single();
        var hintBlock = queuePanel.GetVisualDescendants()
            .OfType<TextBlock>()
            .FirstOrDefault(tb => tb.Text?.StartsWith("or open Settings", StringComparison.Ordinal) == true);

        Assert.NotNull(hintBlock);

        // ── Assert: hint is NOT clipped by the fixed 280 px panel ──
        // Guard: arranged width is sensible (not collapsed to zero).
        Assert.True(hintBlock.Bounds.Width > 20,
            $"Hint TextBlock arranged width {hintBlock.Bounds.Width:F1} px should be > 20 px.");

        // The right edge of the hint, translated into QueuePanel coordinates,
        // must be ≤ 280 px (the fixed panel width).  When the hint is laid out
        // horizontally beside the button, its right edge is ~341 px and fails
        // this assertion.  After stacking vertically with TextWrapping="Wrap",
        // it fits within the panel.
        var rightEdgeInPanel = hintBlock.TranslatePoint(
            new Point(hintBlock.Bounds.Width, 0), queuePanel);

        Assert.NotNull(rightEdgeInPanel);
        Assert.True(
            rightEdgeInPanel.Value.X <= 280.0,
            $"Hint right edge at {rightEdgeInPanel.Value.X:F1} px should be ≤ 280 px QueuePanel width. "
            + "Hint is clipped when laid out horizontally beside the button.");
    }
}
